const loadModuleResolverPlugin = require('./loadModuleResolverPlugin');
const resolveAliases = require('./resolveAliases');
const {
  resolveJestAliases,
  resolveStorybookAliases,
  resolveVitestAliases,
} = require('./aliases');

/**
 * @returns {Record<string,string|string[]> | null}
 */
function resolveWebpackAliases() {
  // @ts-expect-error - real return type
  return resolveAliases({
    isWebpack: true,
    isExternal: false,
  });
}

module.exports = {
  loadModuleResolverPlugin,
  resolveJestAliases,
  resolveVitestAliases,
  resolveStorybookAliases,
  resolveWebpackAliases,
};
